"""family_golf7_3: cheaper EXACT golf solvers for targets in slice [3::4].

Technique
---------
The integrated best solutions for these 45 target tasks were all emitted in
float32, so every intermediate tensor costs 4 bytes/element.  Since the grader
only thresholds ``(output > 0)`` (see neurogolf_utils.run_network), the entire
computation can run in float16 with identical EXACT results, halving the
dominant intermediate-memory term of the cost (cost = params + memory).

For each target we take the existing exact graph and re-emit it in float16:
  * cast the float32 ``input`` to float16 once at the top,
  * convert every float initializer / Constant to float16 (values clamped to
    the representable range so large sentinels stay finite),
  * retarget intermediate ``Cast``-to-float32 nodes to float16,
  * declare the graph ``output`` as float16 (the grader thresholds it anyway).
This yields ~+0.3..+0.7 pts per task with no change in behaviour.

Detection is behavioural and self-contained: each embedded float16 graph is run
(via onnxruntime) on the task's train+test pairs; it is proposed only when it
reproduces every pair EXACTLY after the (>0) threshold.  Wrong tasks therefore
never fire (and the grader still validates arc-gen), so it generalises without
memorising example contents.
"""
from __future__ import annotations

import base64
import gzip

import numpy as np
import onnx

try:
    import onnxruntime as _ort
except Exception:  # pragma: no cover
    _ort = None

# task-number -> gzip+base64 of the float16 ONNX model
_MODELS = {
    13: "",
    14: "",
    27: "",
    29: "",
    33: "",
    37: "",
    40: "",
    57: "",
    61: "",
    62: "",
    63: "",
    65: "",
    68: "",
    71: "",
    90: "",
    92: "",
    93: "",
    102: "",
    109: "",
    110: "",
    112: "",
    121: "",
    122: "",
    124: "",
    125: "",
    131: "",
    162: "",
    197: "",
    198: "",
    221: "",
    228: "",
    253: "",
    259: "",
    273: "",
    279: "",
    284: "",
    286: "",
    305: "",
    316: "",
    328: "",
    335: "",
    346: "",
    381: "",
    390: "",
    400: "",
}

_SESS = {}


def _raw(t):
    return gzip.decompress(base64.b64decode(_MODELS[t]))


def _session(t):
    s = _SESS.get(t)
    if s is None:
        so = _ort.SessionOptions()
        so.graph_optimization_level = _ort.GraphOptimizationLevel.ORT_DISABLE_ALL
        so.log_severity_level = 3
        s = _ort.InferenceSession(_raw(t), so)
        _SESS[t] = s
    return s


def _onehot(grid):
    g = np.asarray(grid, dtype=np.int64)
    h, w = g.shape
    x = np.zeros((1, 10, 30, 30), dtype=np.float32)
    for r in range(h):
        row = g[r]
        for c in range(w):
            x[0, int(row[c]), r, c] = 1.0
    return x


def candidates(examples):
    if _ort is None:
        return []
    pairs = list(examples.get("train", [])) + list(examples.get("test", []))
    data = []
    for e in pairs:
        gi = np.asarray(e["input"]); go = np.asarray(e["output"])
        if gi.ndim != 2 or go.ndim != 2:
            continue
        if max(gi.shape) > 30 or max(go.shape) > 30:
            continue  # grader ignores >30x30 grids
        data.append((_onehot(gi), _onehot(go)))
    if not data:
        return []
    out = []
    for t in _MODELS:
        try:
            sess = _session(t)
        except Exception:
            continue
        ok = True
        for x, tg in data:
            try:
                y = sess.run(["output"], {"input": x})[0]
            except Exception:
                ok = False
                break
            yb = (np.asarray(y) > 0.0)
            if yb.shape != tg.shape or not np.array_equal(yb, tg > 0.0):
                ok = False
                break
        if ok:
            try:
                out.append((f"g73_f16_{t}", onnx.load_from_string(_raw(t))))
            except Exception:
                pass
    return out
